import React from 'react';
import Icon from '../../../components/AppIcon';
import Button from '../../../components/ui/Button';
import Image from '../../../components/AppImage';

const ReservationCard = ({ reservation, onViewTimeline, onAccept, onReject, onViewContract }) => {
  const formatDate = (dateString) => {
    const date = new Date(dateString);
    return date?.toLocaleDateString('fr-FR', {
      day: '2-digit',
      month: 'short',
      year: 'numeric'
    });
  };

  const formatDateTime = (dateString) => {
    const date = new Date(dateString);
    return date?.toLocaleDateString('fr-FR', {
      day: '2-digit',
      month: 'long',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  const getCautionStatusConfig = (status) => {
    const configs = {
      pending: { label: 'En attente', color: 'text-muted-foreground' },
      authorized: { label: 'Autorisée', color: 'text-success' },
      released: { label: 'Libérée', color: 'text-success' },
      captured: { label: 'Capturée', color: 'text-warning' }
    };
    return configs?.[status] || configs?.pending;
  };

  const getStatusConfig = (status) => {
    const configs = {
      pending: { label: 'En attente', color: 'bg-warning/10 text-warning', icon: 'Clock' },
      accepted: { label: 'Acceptée', color: 'bg-success/10 text-success', icon: 'CheckCircle' },
      rejected: { label: 'Refusée', color: 'bg-danger/10 text-danger', icon: 'XCircle' },
      ongoing: { label: 'En cours', color: 'bg-primary/10 text-primary', icon: 'Activity' },
      completed: { label: 'Terminée', color: 'bg-success/10 text-success', icon: 'CheckCircle' },
      cancelled: { label: 'Annulée', color: 'bg-muted/10 text-muted-foreground', icon: 'XCircle' }
    };
    return configs?.[status] || configs?.pending;
  };

  const cautionConfig = getCautionStatusConfig(reservation?.cautionStatus);
  const statusConfig = getStatusConfig(reservation?.status);

  // Check if 48h have passed since request
  const requestDate = new Date(reservation?.requestDate);
  const now = new Date();
  const hoursSinceRequest = (now - requestDate) / (1000 * 60 * 60);
  const willAutoCancel = reservation?.status === 'pending' && hoursSinceRequest < 48;
  const hoursRemaining = willAutoCancel ? Math.max(0, 48 - hoursSinceRequest) : 0;

  return (
    <div className="bg-white rounded-lg border border-border p-6 hover:shadow-elevation-2 transition-shadow">
      <div className="flex flex-col lg:flex-row gap-4">
        {/* Equipment Image */}
        <div className="w-full lg:w-48 h-48 flex-shrink-0">
          <Image
            src={reservation?.equipmentImage}
            alt={reservation?.equipmentImageAlt}
            className="w-full h-full object-cover rounded-lg"
          />
        </div>

        {/* Reservation Details */}
        <div className="flex-1 space-y-4">
          {/* En-tête */}
          <div className="flex flex-col md:flex-row md:items-start md:justify-between gap-3">
            <div>
              <h3 className="text-xl font-bold text-foreground mb-1">{reservation?.equipmentTitle}</h3>
              <p className="text-sm text-muted-foreground">Référence: {reservation?.id}</p>
            </div>
            <span className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium ${statusConfig?.color} whitespace-nowrap`}>
              <Icon name={statusConfig?.icon} size={14} />
              {statusConfig?.label}
            </span>
          </div>

          {/* Info Grid */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-full overflow-hidden flex-shrink-0">
                <img
                  src={reservation?.renterAvatar}
                  alt={`Avatar de ${reservation?.renterPseudo}`}
                  className="w-full h-full object-cover"
                />
              </div>
              <div>
                <p className="text-xs text-muted-foreground">Locataire</p>
                <p className="font-medium text-foreground">{reservation?.renterPseudo}</p>
              </div>
            </div>

            <div>
              <p className="text-xs text-muted-foreground mb-1">Période de location</p>
              <p className="font-medium text-foreground">
                {formatDate(reservation?.startDate)} - {formatDate(reservation?.endDate)}
              </p>
            </div>

            <div>
              <p className="text-xs text-muted-foreground mb-1">Montant total</p>
              <p className="font-semibold text-foreground text-lg">{reservation?.totalAmount?.toFixed(2)} €</p>
            </div>

            <div>
              <p className="text-xs text-muted-foreground mb-1">Caution</p>
              <p className="font-medium text-foreground">
                {reservation?.cautionAmount?.toFixed(2)} €
                <span className={`ml-2 text-xs ${cautionConfig?.color}`}>({cautionConfig?.label})</span>
              </p>
            </div>
          </div>

          {/* Auto-cancel warning */}
          {willAutoCancel && (
            <div className="bg-warning/10 border border-warning/20 rounded-lg p-3">
              <div className="flex gap-2">
                <Icon name="AlertTriangle" size={16} className="text-warning flex-shrink-0 mt-0.5" />
                <p className="text-xs text-foreground">
                  Cette demande sera automatiquement annulée dans <strong>{Math.floor(hoursRemaining)}h</strong> si vous ne répondez pas.
                </p>
              </div>
            </div>
          )}

          {/* Actions */}
          <div className="flex items-center gap-3 flex-wrap">
            {reservation?.status === 'pending' && (
              <>
                <Button
                  variant="success"
                  size="sm"
                  iconName="CheckCircle"
                  onClick={() => onAccept?.(reservation)}
                >
                  Accepter
                </Button>
                <Button
                  variant="danger"
                  size="sm"
                  iconName="XCircle"
                  onClick={() => onReject?.(reservation)}
                >
                  Refuser
                </Button>
              </>
            )}

            {reservation?.contractUrl && (
              <Button
                variant="outline"
                size="sm"
                iconName="FileText"
                onClick={() => onViewContract?.(reservation)}
              >
                Voir le contrat
              </Button>
            )}

            <Button
              variant="outline"
              size="sm"
              iconName="Clock"
              onClick={() => onViewTimeline?.(reservation)}
            >
              Historique
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ReservationCard;
